import{_ as t,o as i,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"18. Clinical Support Time","description":"","frontmatter":{"title":"18. Clinical Support Time","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/18-clinical-support-time.md","filePath":"ebas/medical-specialists/employment/18-clinical-support-time.md"}'),n={name:"ebas/medical-specialists/employment/18-clinical-support-time.md"};function r(s,e,l,c,p,d){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_18-clinical-support-time" tabindex="-1">18. Clinical Support Time <a class="header-anchor" href="#_18-clinical-support-time" aria-label="Permalink to &quot;18. Clinical Support Time&quot;">​</a></h1><p>The actual quantum of Clinical Support Time allocated to an individual Doctor is to be agreed locally between the Doctor and the Health Service having regard to this clause.</p><p><strong>18.1</strong> Allocation of Clinical Support Time</p><p><strong>(a)</strong> Doctors will be entitled to devote 20% of their normal weekly hours to Clinical Support Duties. Agreement as to the actual proportion of such time allocation will be determined at the commencement of employment and/or as shall be consistent with Specialist Medical College guidelines where applicable.</p><p><strong>(b)</strong> Unit Heads (and above with management roles) will be provided with a minimum 50% clinical support time allocation.</p><p><strong>(c)</strong> Subject to the locally agreed arrangement, a Doctor and Health Service can agree to a proportion of normal weekly hours for Clinical Support Duties less than 20% (or 50% for a Unit Head and above with management roles) of the Doctor’s normal weekly hours.</p><p><strong>18.2</strong> Fractional Doctors working minimal hours</p><p><strong>(a)</strong> In cases where the Health Service has deemed the Fractional Doctor to be working minimal hours, the Health Service is to use the Template Letter in</p><p><strong>(i)</strong> direct the Fractional Doctor in writing not to perform any Clinical Support Duties; and</p><p><strong>(ii)</strong> such a proportion of time for non-clinical activity may not be allocated.</p><p><strong>(b)</strong> The Health Service is to consider the individual circumstances such as current duties and responsibilities when determining whether the Fractional Doctor is working minimal hours.</p><p><strong>(c)</strong> Despite the above, where the Fractional Doctor is required to perform ad-hoc non-clinical activities (e.g. yearly mandatory training) a quantum of paid Clinical Support Time for a fixed period may be agreed between the Doctor and the Chief Medical Officer (or delegate) following discussions with the Head of Unit to facilitate the performance and payment for these ad-hoc non- clinical activities.</p><p><strong>18.3</strong> Forms of ‘Clinical Support Duties’</p><p><strong>(a)</strong> Clinical Support Duties are duties which are agreed by the Employer to be performed by the Doctor and:</p><p><strong>(i)</strong> involve non-direct patient care; and</p><p><strong>(ii)</strong> are important to the performance of a Doctor in public health services to support specific aspects of its operation; and</p><p><strong>(iii)</strong> support:</p><p>A. Operations of the unit and the Health Service</p><p>B. Quality improvement activities</p><p>C. Maintenance of a Doctor’s skills and new skill development</p><p>D. Contribution to teaching and education of medical staff and other health professionals.</p><p><strong>(b)</strong> Indicative examples of Clinical Support Duties include:</p><p><strong>(i)</strong> administration;</p><p><strong>(ii)</strong> attendance at departmental or Health Service meetings (other than clinical meetings focused on patients) and meetings of the medical staff group when related to Health Service business;</p><p><strong>(iii)</strong> CME/CPD/maintenance of professional standards;</p><p><strong>(iv)</strong> quality assurance;</p><p><strong>(v)</strong> research (other than clinical research);</p><p><strong>(vi)</strong> audit and participation in Quality Assurance Activities as required by the Health Service;</p><p><strong>(vii)</strong> post-graduate and undergraduate teaching activities;</p><p><strong>(viii)</strong> reasonable time directly spent in the collection, analysis and presentation of quality assurance data and attendance at scheduled unit/divisional audit meetings;</p><p><strong>(ix)</strong> attendance at committees established under ACHS guidelines, and Inter-unit clinical meetings e.g. Grand Rounds.</p><p><strong>(c)</strong> A Health Service may give preference to Clinical Support Duties that are required to be performed by the Doctor to meet the organisation’s needs.</p><p><strong>(d)</strong> The Health Service may require a Doctor to perform (or not perform) Clinical Support Duties, however, where a Doctor disputes the initial determination of the Health Service, a Doctor may utilise the Dispute Resolution Procedure at clause 11of the Agreement.</p><p><strong>18.4</strong> Pooling of Clinical Support Time</p><p>Following consultation with the Health Service, Doctors within a unit (other than the Unit Head) can agree to pool up to half their individual clinical support time entitlement for use by other Doctors in the unit. Agreement is to be in writing and can be terminated on one month’s notice by the Doctor or the Health Service.</p>',35)])])}const u=t(n,[["render",r]]);export{m as __pageData,u as default};
